import { BaseModel, CastableTypes } from './base-model';
import { Profile } from './profile';
import { Team } from './team';
import { RoleDomain, RoleLevel } from './types';
import { UserRole } from './user-role';

export class User extends BaseModel {
  static _cast: Partial<Record<keyof User, CastableTypes>> = {
    passwordUpdatedDate: 'date',
    createdAt: 'date',
    updatedAt: 'date',
  };

  id!: string;
  email!: string;
  passwordUpdatedDate?: Date | null;
  createdAt?: Date | null;
  updatedAt?: Date | null;
  deletedAt?: Date | null;
  teams: Team[] = [];

  profile!: Profile;
  // teamId-domain-level
  accessibleContents!: Record<
    string,
    Record<
      RoleDomain,
      Record<
        RoleLevel,
        {
          isAccessible: boolean;
          isTeamCrossing: boolean;
        }
      >
    >
  >;
  givenUserRoles: Record<string, UserRole[]> = {};

  static isAccessible(
    user: User | null,
    teamId: string,
    domain: RoleDomain,
    level: RoleLevel,
    needsTeamCrossing: boolean,
  ): boolean {
    const InTeamMap: Record<
      RoleDomain,
      Record<
        RoleLevel,
        {
          isAccessible: boolean;
          isTeamCrossing: boolean;
        }
      >
    > | null =
      user?.accessibleContents[teamId] ?? user?.accessibleContents.all ?? null;
    if (!InTeamMap) {
      return false;
    }
    return (
      InTeamMap[domain][level].isAccessible &&
      (!needsTeamCrossing || InTeamMap[domain][level].isTeamCrossing)
    );
  }

  constructor(data?: any) {
    super();
    this.init(User, data);
    const profile = Profile.newInstance(Profile, data?.profile);
    if (!profile) {
      throw new Error(`No profile: ${data}`);
    }
    this.profile = data.profile;
    this.teams = Team.newInstances(Team, data?.teams);
    for (const teamId in data?.givenUserRoles ?? {}) {
      const roleGroup = data.givenUserRoles[teamId];
      this.givenUserRoles[teamId] = UserRole.newInstances(UserRole, roleGroup);
    }
  }

  // NOTE: These are function overloads, so we need to disable the eslint rules.
  hasBasicWriteAccessFor<T extends RecordWithUserIdAndTeamId>(
    record: T,
  ): boolean;
  // eslint-disable-next-line no-dupe-class-members
  hasBasicWriteAccessFor<T extends RecordWithUserId>(
    record: T,
    teamId: string,
  ): boolean;
  // eslint-disable-next-line no-dupe-class-members
  hasBasicWriteAccessFor<T extends RecordWithUserIdAndTeamId>(
    record: T,
    teamId?: string,
  ) {
    const canWriteAcrossTeam = User.isAccessible(
      this,
      teamId ?? record.teamId,
      'basic',
      'write',
      true,
    );
    const canWriteToOwnRecord = User.isAccessible(
      this,
      teamId ?? record.teamId,
      'basic',
      'write',
      false,
    );
    const isRecordOwner = record.userId !== null && record.userId === this.id;

    return canWriteAcrossTeam || (isRecordOwner && canWriteToOwnRecord);
  }

  getUserRoles(teamId: string): UserRole[] {
    if (!this.givenUserRoles[teamId]) {
      if (Object.keys(this.givenUserRoles).length > 0) {
        return this.givenUserRoles[Object.keys(this.givenUserRoles)[0]];
      }
      return [];
    }

    return this.givenUserRoles[teamId];
  }
}

interface RecordWithUserId {
  userId: string | null;
}

interface RecordWithUserIdAndTeamId {
  userId: string | null;
  teamId: string;
}

