import {
  Alert,
  Box,
  Button,
  Container,
  Divider,
  Stack,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import moment from 'moment';
import { enqueueSnackbar } from 'notistack';
import React, { ReactElement, useEffect, useMemo, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import DefaultBreadCrumbs from '@/components/common/default-breadcrumb';
import { ConfirmationModal } from '@/components/modal/confirmation-modal';
import NotificationEditor, {
  NotificationUpdateParam,
} from '@/components/notifications/notification-editor';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import { wrapForLoading } from '@/utils/functions/transformer';
import { translate } from '@/utils/i18n';

function PageInner({
  currentUser,
  currentTeam,
  notificationId,
}: {
  currentUser: User;
  currentTeam: Team;
  notificationId: string;
}) {
  const { services, router, reloader } = useServicesHook();
  const unit = useSelector((state) => state.user.unit);

  const teamId = currentTeam.id;

  const timezone = useMemo(
    () => Intl.DateTimeFormat().resolvedOptions().timeZone,
    [],
  );

  const [isInitialized, setIsInitialized] = useState<boolean>(false);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [confirmModalDataIsOpen, setConfirmModalDataIsOpen] =
    useState<boolean>(false);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [error, setError] = useState<ServiceError | null>(null);
  const [notification, setNotification] = useState<NotificationUpdateParam>({
    titleEn: '',
    titleJa: '',
    contentsEn: '',
    contentsJa: '',
    targetType: 'common',
    targetTeamTypes: 'multiple',
    publishAtDate: '',
    publishAtTime: '',
    isImportant: false,
  });

  const hasSuperUserReadAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'read',
    false,
  );

  const hasSuperUserWriteAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'write',
    false,
  );

  const getNotification = async () => {
    const { notification, error } =
      await services.default.superAdmin.getNotification(notificationId);

    if (error) {
      setLoadError(error);
      return;
    }

    setLoadError(null);
    // Convert API response to UI format
    const apiTargetTeamTypes = notification.targetTeamTypes || ['multiple'];
    let uiTargetTeamTypes: 'single' | 'multiple' | 'all' = 'multiple';

    if (apiTargetTeamTypes.includes('all')) {
      uiTargetTeamTypes = 'all';
    } else if (
      apiTargetTeamTypes.includes('multiple') &&
      apiTargetTeamTypes.includes('single')
    ) {
      uiTargetTeamTypes = 'all';
    } else if (apiTargetTeamTypes.includes('single')) {
      uiTargetTeamTypes = 'single';
    } else {
      uiTargetTeamTypes = 'multiple';
    }

    setNotification({
      titleEn: notification.title.en,
      titleJa: notification.title.ja,
      contentsEn: notification.contents.en,
      contentsJa: notification.contents.ja,
      targetType: notification.targetType,
      targetTeamTypes: uiTargetTeamTypes,
      publishAtDate: moment(notification.publishAt).format('YYYY-MM-DD'),
      publishAtTime: moment(notification.publishAt).format('HH:mm:ss'),
      isImportant: notification.isImportant,
    });
  };

  const deleteNotification = async () => {
    await wrapForLoading(setIsSubmitting, async () => {
      const { error } =
        await services.default.superAdmin.deleteNotification(notificationId);
      if (error) {
        setError(error);
        return;
      }

      enqueueSnackbar({
        variant: 'success',
        message: translate('the_data_is_successfully_deleted'),
      });

      router.replace(PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href());
    });
  };

  const updateNotification = async (data: NotificationUpdateParam) => {
    await wrapForLoading(setIsSubmitting, async () => {
      // Convert radio button value to API format
      const apiTargetTeamTypes =
        data.targetTeamTypes === 'all'
          ? ['multiple', 'single']
          : [data.targetTeamTypes];

      const { notification, error } =
        await services.default.superAdmin.updateNotification(notificationId, {
          titleEn: data.titleEn,
          titleJa: data.titleJa,
          contentsEn: data.contentsEn,
          contentsJa: data.contentsJa,
          targetType: data.targetType,
          targetTeamTypes: apiTargetTeamTypes,
          publishAt:
            data.publishAtDate && data.publishAtTime
              ? moment(
                  `${moment(data.publishAtDate).format('YYYY-MM-DD')} ${data.publishAtTime}`,
                ).toDate()
              : null,
          isImportant: data.isImportant ?? false,
        });
      if (error) {
        setError(error);
        return;
      }

      enqueueSnackbar({
        variant: 'success',
        message: translate('the_data_is_successfully_updated'),
      });
    });
  };

  const initialize = async () => {
    try {
      await Promise.all([getNotification()]);
    } finally {
      setIsInitialized(true);
    }
  };

  useEffect(() => {
    reloader.reloadIfNeeded();
    initialize();
  }, []);

  if (!hasSuperUserReadAccess || !notification) {
    return (
      <Container>
        <Alert severity="error">
          このページにアクセスする権限がありません。
        </Alert>
      </Container>
    );
  }

  return (
    <Container
      sx={{
        position: 'relative',
        'input, .MuiSelect-select': {
          backgroundColor: 'white',
        },
      }}
    >
      <ConfirmationModal
        isOpen={confirmModalDataIsOpen}
        setIsOpen={setConfirmModalDataIsOpen}
        isDeleteMode={true}
        title={translate('delete_notification')}
        cbOk={() => {
          deleteNotification();
        }}
        onClose={() => {
          setConfirmModalDataIsOpen(false);
        }}
      />
      <DefaultBreadCrumbs
        breadcrumbs={[
          {
            name: translate(
              PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS
                .name as keyof typeof translate,
            ),
            link: PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
          },
          {
            name: translate(
              PAGE_INFO.SUPER_ADMIN_NOTIFICATION.name as keyof typeof translate,
            ),
            link: PAGE_INFO.SUPER_ADMIN_NOTIFICATION.href(notificationId),
          },
        ]}
      />
      <Typography variant="h1">{translate('notification')}</Typography>
      <Divider sx={{ mt: 1, mb: 5 }} />
      {loadError ? (
        <CriticalError error={loadError} />
      ) : (
        <>
          <NotificationEditor
            notification={notification}
            setNotification={setNotification}
            error={error}
          />
          {hasSuperUserWriteAccess ? (
            <Stack
              direction="row"
              sx={{
                mt: 4,
              }}
            >
              <Button
                color="primary"
                variant="contained"
                loading={isSubmitting}
                onClick={() => {
                  updateNotification(notification);
                }}
              >
                {translate('button_save_changes')}
              </Button>
              <Box flexGrow={1} display="flex" justifyContent="flex-end">
                <Button
                  color="error"
                  variant="contained"
                  loading={isSubmitting}
                  onClick={() => {
                    setConfirmModalDataIsOpen(true);
                  }}
                >
                  {translate('delete')}
                </Button>
              </Box>
            </Stack>
          ) : <></>}
        </>
      )}
    </Container>
  );
}

export default function Page() {
  const { router } = useServicesHook();

  const currentUser = useSelector((state) => state.user.me);
  const currentTeam = useSelector((state) => state.user.currentTeam);
  const notificationId = router.query.notification_id?.toString();

  return (
    currentUser &&
    currentTeam &&
    notificationId && (
      <PageInner
        currentUser={currentUser}
        currentTeam={currentTeam}
        notificationId={notificationId}
      />
    )
  );
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

import {
  Alert,
  Box,
  Button,
  Card,
  Container,
  Divider,
  Paper,
  Stack,
  TableContainer,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import moment from 'moment';
import Link from 'next/link';
import React, { ReactElement, useEffect, useMemo, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import DefaultBreadCrumbs from '@/components/common/default-breadcrumb';
import DefaultSearchField from '@/components/common/input/default-search-field';
import {
  LinkableTable as Table,
  LinkableTableBody as TableBody,
  LinkableTableCell as TableCell,
  LinkableTableHead as TableHead,
  LinkableTableRow as TableRow,
} from '@/components/common/linkable-table';
import {
  CommonPagination,
  CommonPaginationData,
} from '@/components/pagination/common-pagination';
import { SupportedLanguage } from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import ConsoleLayout from '@/layouts/console.layout';
import { Notification } from '@/models/notification';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { useSelector } from '@/store';
import { getDefaultLanguage, translate } from '@/utils/i18n';
import { PathUtil } from '@/utils/path.util';

type NotificationsQueryCondition = {
  keyword: string;
  searchTrigger: Date;
};

const defaultCondition: NotificationsQueryCondition & CommonPaginationData = {
  keyword: '',
  currentPage: 0,
  rowsPerPage: 10,

  searchTrigger: new Date(),
};

const buildQueryParam = (
  data: NotificationsQueryCondition & CommonPaginationData,
) => {
  return {
    keyword: data.keyword.toString(),
    page: data.currentPage.toString(),
    pageSize: data.rowsPerPage.toString(),
  };
};

const parseQueryParam = (data: any) => {
  return _.chain({
    keyword: PathUtil.getStringFromQuery(data.keyword),
    currentPage: PathUtil.getIntFromQuery(data.page),
    rowsPerPage: PathUtil.getIntFromQuery(data.pageSize),
  })
    .omitBy((v, k) => {
      return _.isNil(v);
    })
    .defaultsDeep(defaultCondition)
    .value();
};

function PageInner({ currentUser }: { currentUser: User }) {
  const { services, router, reloader } = useServicesHook();

  const now = new Date();

  const [currentLang, setCurrentLang] =
    useState<SupportedLanguage>(getDefaultLanguage());

  const [isInitialized, setIsInitialized] = useState<boolean>(false);
  const [loadError, setLoadError] = useState<ServiceError | null>(null);
  const [conditions, setConditions] = useState<
    NotificationsQueryCondition & CommonPaginationData
  >({
    ...defaultCondition,
    ...parseQueryParam(router.query),
    ...services.localStorage.defaultPaginationData(
      currentUser.id,
      router.query,
    ),
  });
  const [numberOfTotalItems, setNumberOfTotalItems] = useState<number>(0);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const targetMap = useMemo(() => {
    return {
      common: translate('notification_target_common_short'),
      web: translate('notification_target_web_short'),
      mobile: translate('notification_target_mobile_short'),
    };
  }, []);

  const teamTypeMap = useMemo(() => {
    return {
      single: translate('team_type_single_short'),
      multiple: translate('team_type_multiple_short'),
      all: translate('team_type_all_short'),
    };
  }, []);

  const formatTargetTeamTypes = (targetTeamTypes: string[]): string => {
    if (!targetTeamTypes || targetTeamTypes.length === 0) {
      return teamTypeMap.multiple;
    }

    // 'all'が含まれているか、'single'と'multiple'の両方が含まれている場合は'all'を返す
    if (
      targetTeamTypes.includes('all') ||
      (targetTeamTypes.includes('single') &&
        targetTeamTypes.includes('multiple'))
    ) {
      return teamTypeMap.all;
    }

    return targetTeamTypes
      .map((type) => teamTypeMap[type as keyof typeof teamTypeMap] || type)
      .join(', ');
  };

  const hasSuperUserReadAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'read',
    false,
  );

  const hasSuperUserWriteAccess = User.isAccessible(
    currentUser,
    'all',
    'admin',
    'write',
    false,
  );

  const getNewNotificationPageLink = () => {
    return PAGE_INFO.SUPER_ADMIN_NOTIFICATION_NEW.href();
  };

  const getDetailPageLink = (notif: Notification) => {
    return PAGE_INFO.SUPER_ADMIN_NOTIFICATION.href(notif.id);
  };

  const getNotifications = async () => {
    const { notifications, total, error } =
      await services.default.superAdmin.getNotifications({
        keyword: conditions.keyword,
        offset: conditions.currentPage * conditions.rowsPerPage,
        pageSize: conditions.rowsPerPage,
      });

    if (error) {
      setLoadError(error);
      return;
    }

    setLoadError(null);
    setNotifications(notifications);
    setNumberOfTotalItems(total);
  };

  const initialize = async () => {
    try {
      setCurrentLang(
        services.localStorage.getLanguage(null) ?? getDefaultLanguage(),
      );
      await Promise.all([getNotifications()]);
      const parsed = {
        ...parseQueryParam(router.query),
        ...services.localStorage.defaultPaginationData(
          currentUser.id,
          router.query,
        ),
      };
      setConditions({
        ...conditions,
        ...parsed,
      });
      updateQueryParameters({
        ...parsed,
        searchTrigger: new Date(),
      });
    } finally {
      setIsInitialized(true);
    }
  };

  const updateQueryParameters = (
    conds: NotificationsQueryCondition & CommonPaginationData,
  ) => {
    const param = buildQueryParam(conds);
    PathUtil.routerPushOrReplaceWithPaginationData(
      router,
      conds.currentPage,
      PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(param),
    );
  };

  // This must be configured for browser back.
  useEffect(() => {
    if (!isInitialized) {
      return;
    }
    // Important: Call after setConditions to trigger (*1)
    const parsed = parseQueryParam(router.query);
    setConditions({
      ...conditions,
      ...parsed,
      searchTrigger: new Date(),
    });
  }, [router.query]); // browser back -> trigger by paginationData

  useEffect(() => {
    // (*1
    if (!isInitialized) {
      return;
    }
    getNotifications();
  }, [conditions.searchTrigger]);

  useEffect(() => {
    reloader.reloadIfNeeded();
    initialize();
  }, []);

  if (!hasSuperUserReadAccess) {
    return (
      <Container>
        <Alert severity="error">
          このページにアクセスする権限がありません。
        </Alert>
      </Container>
    );
  }

  return (
    <Container sx={{ position: 'relative' }}>
      <DefaultBreadCrumbs
        breadcrumbs={[
          {
            name: translate(
              PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS
                .name as keyof typeof translate,
            ),
            link: PAGE_INFO.SUPER_ADMIN_NOTIFICATIONS.href(),
          },
        ]}
      />
      <Stack direction="row">
        <Typography variant="h1">{translate('all_notifications')}</Typography>
        <Box
          display="flex"
          flexGrow={1}
          justifyContent="flex-end"
          alignItems="center"
        >
        {hasSuperUserWriteAccess ? (
          <Link href={getNewNotificationPageLink()}>
            <Button color="primary" variant="contained">
              {translate('create_new_notification')}
            </Button>
          </Link>
        ) : <></>}
        </Box>
      </Stack>
      <Divider sx={{ mt: 1, mb: 5 }} />

      <Card sx={{ border: 'none', p: 2 }}>
        <Stack
          direction="row"
          spacing={1}
          sx={{
            '& .MuiSelect-button ': {
              fontSize: 12,
              fontWeight: 600,
              minWidth: 80,
            },
          }}
        >
          <Box flexGrow={1} display="flex" justifyContent="flex-end">
            <DefaultSearchField
              value={conditions.keyword}
              onSearch={() => {
                const newData = {
                  ...conditions,
                  currentPage: 0,
                };
                updateQueryParameters(newData);
              }}
              onChange={(e) => {
                setConditions({
                  ...conditions,
                  keyword: e.target.value,
                });
              }}
            />
          </Box>
        </Stack>

        {loadError ? (
          <CriticalError error={loadError} />
        ) : (
          <TableContainer
            component={Paper}
            sx={
              {
                // height: "100%",
              }
            }
          >
            <Table
              sx={{
                minWidth: '100%',
                width: 'auto',
                '.MuiTableCell-root': {
                  height: 'auto',
                  px: 0.5,
                  overflowWrap: 'anywhere',
                },
              }}
            >
              <TableHead>
                <TableRow>
                  <TableCell align="left">ID</TableCell>
                  <TableCell align="left">{translate('title')}</TableCell>
                  <TableCell align="left">{translate('contents')}</TableCell>
                  <TableCell align="left">
                    {translate('notification_target_type')}
                  </TableCell>
                  <TableCell align="left">
                    {translate('notification_target_team_types')}
                  </TableCell>
                  <TableCell align="left">
                    {translate('notification_importance')}
                  </TableCell>
                  <TableCell align="left">
                    {translate('publish_date')}
                  </TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {notifications.map((notification) => (
                  <TableRow
                    component={Link}
                    key={notification.id}
                    sx={{
                      '&:last-child .MuiTableCell-root': { border: 0 },
                      '.MuiTableCell-root': {
                        backgroundColor: moment(notification.publishAt).isAfter(
                          now,
                        )
                          ? '#e5f8ff'
                          : 'white',
                      },
                    }}
                    href={getDetailPageLink(notification)}
                  >
                    <TableCell align="left">
                      <Typography
                        variant="inherit"
                        component="span"
                        sx={{
                          wordBreak: 'keep-all',
                        }}
                      >
                        {notification.id}
                      </Typography>
                    </TableCell>
                    <TableCell align="left">
                      {notification.title[currentLang]}
                    </TableCell>
                    <TableCell align="left">
                      {_.truncate(notification.contents[currentLang], {
                        length: 100,
                      })}
                    </TableCell>
                    <TableCell align="left">
                      <Typography
                        component="span"
                        variant="inherit"
                        sx={{
                          overflowWrap: 'normal',
                        }}
                      >
                        {targetMap[notification.targetType]}
                      </Typography>
                    </TableCell>
                    <TableCell align="left">
                      <Typography
                        component="span"
                        variant="inherit"
                        sx={{
                          overflowWrap: 'normal',
                        }}
                      >
                        {formatTargetTeamTypes(notification.targetTeamTypes)}
                      </Typography>
                    </TableCell>
                    <TableCell align="left">
                      {notification.isImportant ? '✓' : ''}
                    </TableCell>
                    <TableCell align="left">
                      {moment(notification.publishAt).format(
                        'YYYY-MM-DD HH:mm:ss',
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}

        <CommonPagination
          user={currentUser}
          numberOfTotalItems={numberOfTotalItems}
          commonPaginationData={{
            currentPage: conditions.currentPage,
            rowsPerPage: conditions.rowsPerPage,
          }}
          onChange={(data) => {
            updateQueryParameters({
              ...conditions,
              ...data,
            });
          }}
        />
      </Card>
    </Container>
  );
}

export default function Page() {
  const currentUser = useSelector((state) => state.user.me);
  return currentUser && <PageInner currentUser={currentUser} />;
}

Page.getLayout = function getLayout(page: ReactElement) {
  return <ConsoleLayout>{page}</ConsoleLayout>;
};

