static isAccessible(
  user: User | null,
  teamId: string,
  domain: RoleDomain,
  level: RoleLevel,
  needsTeamCrossing: boolean,
): boolean {
  const InTeamMap: Record<
    RoleDomain,
    Record<
      RoleLevel,
      {
        isAccessible: boolean;
        isTeamCrossing: boolean;
      }
    >
  > | null =
    user?.accessibleContents[teamId] ?? user?.accessibleContents.all ?? null;
  if (!InTeamMap) {
    return false;
  }
  return (
    InTeamMap[domain][level].isAccessible &&
    (!needsTeamCrossing || InTeamMap[domain][level].isTeamCrossing)
  );
}

